        piece_types = ['b', 'w']
        row_offset = 0
        for i in range(3):
            self.grid[i][::2] = [piece_types[row_offset + j % 2] for j in range(4)]
            self.grid[5 + i][1::2] = [piece_types[row_offset + (j + 1) % 2] for j in range(4)]
        self.print_board()

    def print_board(self):
        for row in self.grid:
            print(" ".join(row or '.'))

    def make_move(self, from_pos, to_pos):
        if self.is_valid_move(from_pos, to_pos):
            self.grid[to_pos[0]][to_pos[1]] = self.grid[from_pos[0]][from_pos[1]]
            self.grid[from_pos[0]][from_pos[1]] = None
            self.print_board()
        else:
            print("Invalid move. Try again.")

    def is_valid_move(self, from_pos, to_pos):
        # Implement move validation logic here
        return True
```

